"use strict";(globalThis.webpackChunksite=globalThis.webpackChunksite||[]).push([[1816],{8333(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/docs/docs/intro","label":"AsiliChain Whitepaper v2","docId":"intro","unlisted":false},{"type":"link","href":"/docs/docs/executive-summary/","label":"1. Executive Summary","docId":"executive-summary/executive-summary","unlisted":false},{"type":"link","href":"/docs/docs/the-problem/value-chain-extraction","label":"2.1 Value Chain Extraction","docId":"the-problem/value-chain-extraction","unlisted":false},{"type":"link","href":"/docs/docs/the-problem/the-eudr-imperative","label":"2.2 The EUDR Imperative","docId":"the-problem/the-eudr-imperative","unlisted":false},{"type":"link","href":"/docs/docs/the-problem/africa-wide-market-opportunity","label":"2.3 Africa-Wide Market Opportunity","docId":"the-problem/africa-wide-market-opportunity","unlisted":false},{"type":"link","href":"/docs/docs/the-problem/","label":"2. The Problem","docId":"the-problem/the-problem","unlisted":false},{"type":"link","href":"/docs/docs/hybrid-chain-architecture/architecture-overview","label":"3.1 Architecture Overview","docId":"hybrid-chain-architecture/architecture-overview","unlisted":false},{"type":"link","href":"/docs/docs/hybrid-chain-architecture/component-breakdown","label":"3.2 Component Breakdown","docId":"hybrid-chain-architecture/component-breakdown","unlisted":false},{"type":"link","href":"/docs/docs/hybrid-chain-architecture/stablecoin-strategy","label":"3.3 Stablecoin Strategy","docId":"hybrid-chain-architecture/stablecoin-strategy","unlisted":false},{"type":"link","href":"/docs/docs/hybrid-chain-architecture/","label":"3. Hybrid Chain Architecture","docId":"hybrid-chain-architecture/hybrid-chain-architecture","unlisted":false},{"type":"link","href":"/docs/docs/revised-loan-flow/gap-in-original-design","label":"4.1 The Gap in the Original Design","docId":"revised-loan-flow/gap-in-original-design","unlisted":false},{"type":"link","href":"/docs/docs/revised-loan-flow/two-leg-settlement-design","label":"4.2 The Two-Leg Settlement Design","docId":"revised-loan-flow/two-leg-settlement-design","unlisted":false},{"type":"link","href":"/docs/docs/revised-loan-flow/why-two-legs","label":"4.3 Why Two Legs Is the Right Design","docId":"revised-loan-flow/why-two-legs","unlisted":false},{"type":"link","href":"/docs/docs/revised-loan-flow/","label":"4. Revised Loan Flow","docId":"revised-loan-flow/revised-loan-flow","unlisted":false},{"type":"link","href":"/docs/docs/chainlink-ccip-bridge/bridge-readiness","label":"5.1 Bridge Readiness","docId":"chainlink-ccip-bridge/bridge-readiness","unlisted":false},{"type":"link","href":"/docs/docs/chainlink-ccip-bridge/trigger-matrix","label":"5.2 What Triggers a Bridge Write","docId":"chainlink-ccip-bridge/trigger-matrix","unlisted":false},{"type":"link","href":"/docs/docs/chainlink-ccip-bridge/what-is-bridged","label":"5.3 What Is Bridged","docId":"chainlink-ccip-bridge/what-is-bridged","unlisted":false},{"type":"link","href":"/docs/docs/chainlink-ccip-bridge/","label":"5. Chainlink CCIP Bridge","docId":"chainlink-ccip-bridge/chainlink-ccip-bridge","unlisted":false},{"type":"link","href":"/docs/docs/failure-modes-and-mitigations/","label":"6. Failure Modes and Mitigations","docId":"failure-modes-and-mitigations/failure-modes","unlisted":false},{"type":"link","href":"/docs/docs/collateral-model/","label":"7. Traceability","docId":"collateral-model/collateral-model","unlisted":false},{"type":"category","label":"7.x Supporting Detail","collapsed":true,"items":[{"type":"link","href":"/docs/docs/collateral-model/growingcroptoken-valuation","label":"7.2 GrowingCropToken Valuation","docId":"collateral-model/growingcroptoken-valuation","unlisted":false},{"type":"link","href":"/docs/docs/collateral-model/credit-score-compounding","label":"7.3 Credit Score Compounding","docId":"collateral-model/credit-score-compounding","unlisted":false}],"collapsible":true},{"type":"link","href":"/docs/docs/07-5-closing-buyer-seller-gap/","label":"7.5 Closing the Buyer-Seller Gap","docId":"07-5-closing-buyer-seller-gap/closing-buyer-seller-gap","unlisted":false},{"type":"link","href":"/docs/docs/07-6-what-a-middleman-actually-does/","label":"7.6 What a Middleman Actually Does","docId":"07-6-what-a-middleman-actually-does/what-a-middleman-actually-does","unlisted":false},{"type":"link","href":"/docs/docs/07-7-how-the-committed-purchase-order-model-works/","label":"7.7 How the Committed Purchase Order Model Works","docId":"07-7-how-the-committed-purchase-order-model-works/how-the-committed-purchase-order-model-works","unlisted":false},{"type":"link","href":"/docs/docs/07-8-what-this-model-actually-eliminates/","label":"7.8 What This Model Actually Eliminates","docId":"07-8-what-this-model-actually-eliminates/what-this-model-actually-eliminates","unlisted":false},{"type":"link","href":"/docs/docs/07-9-value-chain-claim-implications/","label":"7.9 What This Means for the Whitepaper\'s Value Chain Claim","docId":"07-9-value-chain-claim-implications/value-chain-claim-implications","unlisted":false},{"type":"link","href":"/docs/docs/three-lenses/mfi-and-impact-investors","label":"8.1 For MFI Lenders and Impact Investors","docId":"three-lenses/mfi-and-impact-investors","unlisted":false},{"type":"link","href":"/docs/docs/three-lenses/cooperatives-and-unions","label":"8.2 For Cooperatives and Cooperative Unions","docId":"three-lenses/cooperatives-and-unions","unlisted":false},{"type":"link","href":"/docs/docs/three-lenses/european-buyers-and-auditors","label":"8.3 For European Buyers and EUDR Auditors","docId":"three-lenses/european-buyers-and-auditors","unlisted":false},{"type":"link","href":"/docs/docs/three-lenses/","label":"8. AsiliChain Through Three Lenses","docId":"three-lenses/three-lenses","unlisted":false},{"type":"link","href":"/docs/docs/projected-impact-metrics/","label":"9. Projected Impact Metrics","docId":"projected-impact-metrics/projected-impact-metrics","unlisted":false},{"type":"link","href":"/docs/docs/uganda-regulatory-architecture/regulatory-landscape","label":"10.1 The Regulatory Landscape","docId":"uganda-regulatory-architecture/regulatory-landscape","unlisted":false},{"type":"link","href":"/docs/docs/uganda-regulatory-architecture/tiered-lending-framework","label":"10.2 The Tiered Lending Framework","docId":"uganda-regulatory-architecture/tiered-lending-framework","unlisted":false},{"type":"link","href":"/docs/docs/uganda-regulatory-architecture/mobile-money-and-kyc","label":"10.3 Mobile Money and KYC Requirements","docId":"uganda-regulatory-architecture/mobile-money-and-kyc","unlisted":false},{"type":"link","href":"/docs/docs/uganda-regulatory-architecture/regulatory-engagement-sequence","label":"10.4 Regulatory Engagement Sequence","docId":"uganda-regulatory-architecture/regulatory-engagement-sequence","unlisted":false},{"type":"link","href":"/docs/docs/uganda-regulatory-architecture/template-for-other-markets","label":"10.5 Template for Other African Markets","docId":"uganda-regulatory-architecture/template-for-other-markets","unlisted":false},{"type":"link","href":"/docs/docs/uganda-regulatory-architecture/","label":"10. Uganda Regulatory Architecture","docId":"uganda-regulatory-architecture/uganda-regulatory-architecture","unlisted":false},{"type":"link","href":"/docs/docs/eudr-compliance-architecture/what-eudr-requires","label":"11.1 What the EUDR Requires","docId":"eudr-compliance-architecture/what-eudr-requires","unlisted":false},{"type":"link","href":"/docs/docs/eudr-compliance-architecture/asilichain-eudr-mapping","label":"11.2 AsiliChain EUDR Mapping","docId":"eudr-compliance-architecture/asilichain-eudr-mapping","unlisted":false},{"type":"link","href":"/docs/docs/eudr-compliance-architecture/dds-generation-pipeline","label":"11.3 DDS Generation Pipeline","docId":"eudr-compliance-architecture/dds-generation-pipeline","unlisted":false},{"type":"link","href":"/docs/docs/eudr-compliance-architecture/","label":"11. EUDR Compliance Architecture","docId":"eudr-compliance-architecture/eudr-compliance-architecture","unlisted":false},{"type":"link","href":"/docs/docs/chainlink-oracle-integration/lendingvault-implementation","label":"12.1 LendingVault.sol Implementation","docId":"chainlink-oracle-integration/lendingvault-implementation","unlisted":false},{"type":"link","href":"/docs/docs/chainlink-oracle-integration/","label":"12. Chainlink Oracle Integration","docId":"chainlink-oracle-integration/chainlink-oracle-integration","unlisted":false},{"type":"link","href":"/docs/docs/development-roadmap/phase-0-foundation","label":"Phase 0 - Foundation (Weeks 1-8)","docId":"development-roadmap/phase-0-foundation","unlisted":false},{"type":"link","href":"/docs/docs/development-roadmap/phase-1-core-contracts-traceability","label":"Phase 1 - Core Contracts and Traceability (Weeks 9-20)","docId":"development-roadmap/phase-1-core-contracts-traceability","unlisted":false},{"type":"link","href":"/docs/docs/development-roadmap/phase-2-hybrid-introduction","label":"Phase 2 - Hybrid Introduction (Weeks 21-32)","docId":"development-roadmap/phase-2-hybrid-introduction","unlisted":false},{"type":"link","href":"/docs/docs/development-roadmap/phase-3-compliance-scale","label":"Phase 3 - Compliance and Scale (Weeks 33-44)","docId":"development-roadmap/phase-3-compliance-scale","unlisted":false},{"type":"link","href":"/docs/docs/development-roadmap/","label":"13. Development Roadmap","docId":"development-roadmap/development-roadmap","unlisted":false},{"type":"link","href":"/docs/docs/security-considerations/","label":"14. Security Considerations","docId":"security-considerations/security-considerations","unlisted":false},{"type":"link","href":"/docs/docs/revenue-model/","label":"15. Revenue Model","docId":"revenue-model/revenue-model","unlisted":false},{"type":"link","href":"/docs/docs/conclusion/","label":"16. Conclusion","docId":"conclusion/conclusion","unlisted":false},{"type":"link","href":"/docs/docs/references/","label":"17. References","docId":"references/references","unlisted":false},{"type":"link","href":"/docs/docs/research-gaps/","label":"18. Research Gaps and Validation Checklist","docId":"research-gaps/research-gaps","unlisted":false},{"type":"link","href":"/docs/docs/visual-index","label":"19. Visual Index","docId":"visual-index","unlisted":false},{"type":"link","href":"/docs/docs/brand-kit/","label":"Brand Kit","docId":"brand-kit/index","unlisted":false}]},"docs":{"07-5-closing-buyer-seller-gap/closing-buyer-seller-gap":{"id":"07-5-closing-buyer-seller-gap/closing-buyer-seller-gap","title":"7.5 Closing the Buyer-Seller Gap","description":"The Problem AsiliChain Does Not Yet Name","sidebar":"tutorialSidebar"},"07-6-what-a-middleman-actually-does/what-a-middleman-actually-does":{"id":"07-6-what-a-middleman-actually-does/what-a-middleman-actually-does","title":"7.6 What a Middleman Actually Does","description":"Before describing the solution, it is worth being precise about what AsiliChain is actually displacing. A middleman in the coffee supply chain performs four functions, only two of which create genuine value.","sidebar":"tutorialSidebar"},"07-7-how-the-committed-purchase-order-model-works/how-the-committed-purchase-order-model-works":{"id":"07-7-how-the-committed-purchase-order-model-works/how-the-committed-purchase-order-model-works","title":"7.7 How the Committed Purchase Order Model Works","description":"The committed purchase order is an on-chain instrument - a cryptographically signed, enforceable commitment between a buyer and a cooperative - that converts a BatchToken or GrowingCropToken into its highest-value collateral form: the WarehouseReceiptToken.","sidebar":"tutorialSidebar"},"07-8-what-this-model-actually-eliminates/what-this-model-actually-eliminates":{"id":"07-8-what-this-model-actually-eliminates/what-this-model-actually-eliminates","title":"7.8 What This Model Actually Eliminates","description":"The committed purchase order model eliminates specifically the third and fourth middleman functions described above - price discovery asymmetry and predatory credit provision - while leaving physical aggregation and logistics untouched.","sidebar":"tutorialSidebar"},"07-9-value-chain-claim-implications/value-chain-claim-implications":{"id":"07-9-value-chain-claim-implications/value-chain-claim-implications","title":"7.9 What This Means for the Whitepaper\'s Value Chain Claim","description":"The whitepaper states that middlemen capture 60 to 70 percent of the coffee value chain. That figure needs a mechanism attached to it, not just a number. The mechanism is this: middlemen capture that share because they control price information and credit access simultaneously.","sidebar":"tutorialSidebar"},"brand-kit/index":{"id":"brand-kit/index","title":"Brand Kit","description":"Brand system","sidebar":"tutorialSidebar"},"chainlink-ccip-bridge/bridge-readiness":{"id":"chainlink-ccip-bridge/bridge-readiness","title":"5.1 Bridge Readiness","description":"A critical prerequisite for the hybrid architecture is confirmed: Chainlink CCIP is live on both Celo mainnet and Mantle mainnet. This is production infrastructure, not a roadmap item. The Celo-Mantle lane is operational and the CCIP directory confirms active cross-chain lanes and supported tokens including bridged USDC. No bridge needs to be built from scratch - the protocol integrates existing, audited infrastructure.","sidebar":"tutorialSidebar"},"chainlink-ccip-bridge/chainlink-ccip-bridge":{"id":"chainlink-ccip-bridge/chainlink-ccip-bridge","title":"5. Chainlink CCIP Bridge","description":"This chapter defines when and why cross-chain movement is triggered. AsiliChain does not bridge every event by default; it bridges only at specific readiness points to keep costs low while preserving settlement integrity.","sidebar":"tutorialSidebar"},"chainlink-ccip-bridge/trigger-matrix":{"id":"chainlink-ccip-bridge/trigger-matrix","title":"5.2 What Triggers a Bridge Write","description":"Not every on-chain event bridges to Mantle. Bridging too frequently adds cost and latency; bridging too late delays loan origination. The trigger point is the GRADED stage. At that moment, the physical coffee has been weighed and graded by the cooperative agent, the data is canonical and will not change, and the BatchToken is ready to serve as collateral. Before GRADED, the token is still being validated. After GRADED, the LendingVault on Mantle can safely accept the metadata as collateral input.","sidebar":"tutorialSidebar"},"chainlink-ccip-bridge/what-is-bridged":{"id":"chainlink-ccip-bridge/what-is-bridged","title":"5.3 What Is Bridged","description":"The CCIP message carries BatchToken metadata only: token ID, farmer ID, cooperative ID, weight in kg, grade, harvest date, GPS hash, and the IPFS URI of supporting documents. It does not carry the token itself. The BatchToken remains on Celo. A mirror record is created on Mantle for the LendingVault to read. This design keeps the farmer\'s asset on Celo where it was minted and avoids the risks of cross-chain token custody.","sidebar":"tutorialSidebar"},"chainlink-oracle-integration/chainlink-oracle-integration":{"id":"chainlink-oracle-integration/chainlink-oracle-integration","title":"12. Chainlink Oracle Integration","description":"Oracle data is the pricing backbone for pre-harvest collateral valuation and risk controls. This chapter documents the concrete smart-contract integration pattern used to consume Chainlink feeds safely.","sidebar":"tutorialSidebar"},"chainlink-oracle-integration/lendingvault-implementation":{"id":"chainlink-oracle-integration/lendingvault-implementation","title":"12.1 LendingVault.sol Implementation","description":"Figure 19: LendingVault.sol - Chainlink AggregatorV3Interface with staleness guard and timelocked fallback","sidebar":"tutorialSidebar"},"collateral-model/collateral-model":{"id":"collateral-model/collateral-model","title":"7. Traceability","description":"AsiliChain treats traceability as the root of collateral. Every stage below adds a new layer of evidence, until the farmer\'s crop can be financed, graded, warehoused, and ultimately settled against a buyer commitment.","sidebar":"tutorialSidebar"},"collateral-model/credit-score-compounding":{"id":"collateral-model/credit-score-compounding","title":"7.3 Credit Score Compounding","description":"CreditScore.sol starts every farmer at 500. Every on-time repayment adds 50 points; every default subtracts 100. The score is public, immutable, and portable across cooperatives and lenders. Over two or three seasons, a farmer who participates faithfully can access materially higher LTVs and lower rates than a new entrant. The score becomes an asset in itself - a credit history that no intermediary can confiscate.","sidebar":"tutorialSidebar"},"collateral-model/growingcroptoken-valuation":{"id":"collateral-model/growingcroptoken-valuation","title":"7.2 GrowingCropToken Valuation","description":"Figure 10: GrowingCropToken valuation formula","sidebar":"tutorialSidebar"},"conclusion/conclusion":{"id":"conclusion/conclusion","title":"16. Conclusion","description":"AsiliChain is underwriting infrastructure. The traceability record, the collateral token, and the EUDR Due Diligence Statement are not three separate products - they are three outputs from the same on-chain data record that the cooperative agent creates when they weigh a farmer\'s batch and log it to the blockchain. Building one builds all three.","sidebar":"tutorialSidebar"},"development-roadmap/development-roadmap":{"id":"development-roadmap/development-roadmap","title":"13. Development Roadmap","description":"The roadmap spans 44 weeks to accommodate phased delivery of core contracts, hybrid chain integration, and compliance scaling. Each phase closes with a hard milestone on mainnet, and the decision gates after Phase 1 and Phase 2 are explicit go or no-go checkpoints based on field and protocol data.","sidebar":"tutorialSidebar"},"development-roadmap/phase-0-foundation":{"id":"development-roadmap/phase-0-foundation","title":"Phase 0 - Foundation (Weeks 1-8)","description":"Milestone: Dev environment live on Celo Alfajores. Company registered. USSD shortcode submitted. UCDA partnership conversation initiated.","sidebar":"tutorialSidebar"},"development-roadmap/phase-1-core-contracts-traceability":{"id":"development-roadmap/phase-1-core-contracts-traceability","title":"Phase 1 - Core Contracts and Traceability (Weeks 9-20)","description":"Milestone Proceed to Mantle or stay Celo-only.","sidebar":"tutorialSidebar"},"development-roadmap/phase-2-hybrid-introduction":{"id":"development-roadmap/phase-2-hybrid-introduction","title":"Phase 2 - Hybrid Introduction (Weeks 21-32)","description":"Milestone Evaluate bridge performance and stablecoin UX.","sidebar":"tutorialSidebar"},"development-roadmap/phase-3-compliance-scale":{"id":"development-roadmap/phase-3-compliance-scale","title":"Phase 3 - Compliance and Scale (Weeks 33-44)","description":"Milestone: First EUDR DDS accepted by EU buyer. 5,000 farmers onboarded. Protocol fee active. Full hybrid system audited. Continental expansion preparation.","sidebar":"tutorialSidebar"},"eudr-compliance-architecture/asilichain-eudr-mapping":{"id":"eudr-compliance-architecture/asilichain-eudr-mapping","title":"11.2 AsiliChain EUDR Mapping","description":"| EUDR Requirement | AsiliChain Implementation |","sidebar":"tutorialSidebar"},"eudr-compliance-architecture/dds-generation-pipeline":{"id":"eudr-compliance-architecture/dds-generation-pipeline","title":"11.3 DDS Generation Pipeline","description":"Figure 18: Automated EUDR DDS generation pipeline","sidebar":"tutorialSidebar"},"eudr-compliance-architecture/eudr-compliance-architecture":{"id":"eudr-compliance-architecture/eudr-compliance-architecture","title":"11. EUDR Compliance Architecture","description":"EUDR compliance requires a defensible evidence pipeline, not just declarations. This chapter maps legal requirements to AsiliChain data outputs and shows how the Due Diligence Statement package is generated from operational events.","sidebar":"tutorialSidebar"},"eudr-compliance-architecture/what-eudr-requires":{"id":"eudr-compliance-architecture/what-eudr-requires","title":"11.1 What the EUDR Requires","description":"Under Article 4 of EU Regulation 2023/1115, every shipment of coffee entering the EU requires a Due Diligence Statement containing GPS polygon coordinates for every plot of land in the supply chain, deforestation-free proof against a December 2020 baseline, proof of legal production under local law, and operator declarations. The GPS polygon requirement alone is structurally impossible with paper-based cooperative records.","sidebar":"tutorialSidebar"},"executive-summary/executive-summary":{"id":"executive-summary/executive-summary","title":"1. Executive Summary","description":"AsiliChain addresses two linked constraints in African coffee value chains: extraction by intermediaries and exclusion from formal credit.","sidebar":"tutorialSidebar"},"failure-modes-and-mitigations/failure-modes":{"id":"failure-modes-and-mitigations/failure-modes","title":"6. Failure Modes and Mitigations","description":"Every serious technical partner - an MFI credit committee, a government ministry IT team, a European buyer\'s procurement officer - will ask what happens when a component fails. This section provides explicit answers. The system is designed with the assumption that any component can fail at any time, and that no single failure should halt the entire protocol or strand a farmer\'s funds.","sidebar":"tutorialSidebar"},"hybrid-chain-architecture/architecture-overview":{"id":"hybrid-chain-architecture/architecture-overview","title":"3.1 Architecture Overview","description":"AsiliChain uses three chains with distinct, non-overlapping responsibilities. Celo handles all farmer-facing interactions the LendingVault, credit scoring, EUDR DDS generation, and USDC settlement with MFI partners. Hedera HCS is the independent, append-only audit log that neither chain can modify and that both chains write to - the single source of truth for regulators and European buyers.","sidebar":"tutorialSidebar"},"hybrid-chain-architecture/component-breakdown":{"id":"hybrid-chain-architecture/component-breakdown","title":"3.2 Component Breakdown","description":"| Layer | Blockchain | Primary Responsibility | Key Technology |","sidebar":"tutorialSidebar"},"hybrid-chain-architecture/hybrid-chain-architecture":{"id":"hybrid-chain-architecture/hybrid-chain-architecture","title":"3. Hybrid Chain Architecture","description":"Core principle: separate farmer simplicity from institutional compliance. The two audiences have fundamentally different needs, and no single chain serves both optimally. This chapter defines the architectural split that keeps field operations lightweight while preserving institutional-grade auditability.","sidebar":"tutorialSidebar"},"hybrid-chain-architecture/stablecoin-strategy":{"id":"hybrid-chain-architecture/stablecoin-strategy","title":"3.3 Stablecoin Strategy","description":"The stablecoin choices are not arbitrary. Each is selected for a specific use case and audience. cUSD on Celo is chosen because Kotani Pay\'s conversion rails to MTN Mobile Money Uganda are live and production-tested today. USDC on Mantle is chosen as the institutional settlement currency because it is MiCA-compliant for EU buyer interactions, has the deepest institutional acceptance of any stablecoin in regulated finance, and is natively supported on Mantle. AUSD from Agora is noted as a future treasury option once Agora formally expands its institutional onboarding programme to East African financial institutions.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"AsiliChain Whitepaper v2","description":"This documentation is a structured markdown version of AsiliChain Protocol Whitepaper v2.0 (April 2026).","sidebar":"tutorialSidebar"},"projected-impact-metrics/projected-impact-metrics":{"id":"projected-impact-metrics/projected-impact-metrics","title":"9. Projected Impact Metrics","description":"The following metrics are projections, not actuals. They are grounded in cited comparable programmes in East Africa. Investors and partners should treat these as directionally informed targets, not guarantees. As real data is generated from Phase 1 onward, these projections will be replaced with measured outcomes.","sidebar":"tutorialSidebar"},"references/references":{"id":"references/references","title":"17. References","description":"- EU Regulation 2023/1115 on Deforestation-Free Products (EUDR). European Parliament and Council, June 2023. https://eur-lex.europa.eu/legal-content/EN/TXT/PDF/?uri=CELEX%3A32023R1115","sidebar":"tutorialSidebar"},"research-gaps/research-gaps":{"id":"research-gaps/research-gaps","title":"18. Research Gaps and Validation Checklist","description":"This chapter tracks the assumptions that still need field validation before scale rollout. It is meant to be a living risk and evidence ledger for product, policy, and market execution.","sidebar":"tutorialSidebar"},"revenue-model/revenue-model":{"id":"revenue-model/revenue-model","title":"15. Revenue Model","description":"AsiliChain is a protocol, not a middleman. Revenue is earned from value added to the system. The protocol deliberately carries no token at this stage. Token economics introduce regulatory risk and community management overhead that is premature before the core protocol has demonstrated product-market fit.","sidebar":"tutorialSidebar"},"revised-loan-flow/gap-in-original-design":{"id":"revised-loan-flow/gap-in-original-design","title":"4.1 The Gap in the Original Design","description":"The previous architecture contained an unresolved assumption: if the LendingVault issues a loan in USDC on Mantle, how does that USDC reach the farmer\'s MTN Mobile Money account? Kotani Pay operates on Celo rails specifically, converting cUSD to MoMo. Simply issuing USDC on Mantle creates a broken payment path. This section defines the two-leg settlement design that closes that gap.","sidebar":"tutorialSidebar"},"revised-loan-flow/revised-loan-flow":{"id":"revised-loan-flow/revised-loan-flow","title":"4. Revised Loan Flow","description":"The loan flow is redesigned around real constraints in cooperative finance: delayed buyer settlement, seasonal liquidity gaps, and the need for risk-controlled disbursement. This chapter explains how AsiliChain separates value transfer legs to improve repayment reliability.","sidebar":"tutorialSidebar"},"revised-loan-flow/two-leg-settlement-design":{"id":"revised-loan-flow/two-leg-settlement-design","title":"4.2 The Two-Leg Settlement Design","description":"Loan disbursement uses a two-leg approach. Leg One the cooperative\'s backend service, triggered by the Mantle settlement event, calls Kotani Pay\'s API on Celo, converting the equivalent amount from the cooperative\'s Celo cUSD reserve to MTN Mobile Money for the farmer. The cooperative manages a float of cUSD on Celo that is periodically replenished from its Mantle USDC balance via a Chainlink CCIP transfer.","sidebar":"tutorialSidebar"},"revised-loan-flow/why-two-legs":{"id":"revised-loan-flow/why-two-legs","title":"4.3 Why Two Legs Is the Right Design","description":"The two-leg approach is more complex than a single-chain design but it is the correct architecture for three reasons. First, it keeps the farmer experience entirely on Celo rails, which are proven and live. The farmer never interacts with Mantle and never needs to know it exists. Second, it keeps the institutional audit trail entirely on Mantle, where MFI partners and regulatory counterparties have a clean USDC-denominated record of every loan. Third, the cooperative float model means the bridging cost of CCIP is amortised across many disbursements rather than paid per loan, which is economically efficient at cooperative scale.","sidebar":"tutorialSidebar"},"security-considerations/security-considerations":{"id":"security-considerations/security-considerations","title":"14. Security Considerations","description":"| Risk Area | Mitigation |","sidebar":"tutorialSidebar"},"the-problem/africa-wide-market-opportunity":{"id":"the-problem/africa-wide-market-opportunity","title":"2.3 Africa-Wide Market Opportunity","description":"Uganda is the entry point. Ethiopia, Kenya, Rwanda, Tanzania, and Burundi face identical traceability deficits and EUDR exposure. AsiliChain\'s architecture is designed from the start to be replicated across cooperative structures and regulatory environments with country-specific customisation of the USSD flow, GPS boundary tool, and language layer.","sidebar":"tutorialSidebar"},"the-problem/the-eudr-imperative":{"id":"the-problem/the-eudr-imperative","title":"2.2 The EUDR Imperative","description":"Under Article 4 of EU Regulation 2023/1115, operators placing coffee on the EU market must file a Due Diligence Statement for every shipment, containing GPS polygon coordinates for every plot of land in the supply chain, deforestation-free proof verified against a 2020 baseline, and a declaration of legal production. For cooperatives sourcing from hundreds of smallholder farms, this is structurally impossible with paper records.","sidebar":"tutorialSidebar"},"the-problem/the-problem":{"id":"the-problem/the-problem","title":"2. The Problem","description":"AsiliChain is built to solve a compound problem: farmer underfinancing, opaque value-chain pricing, and rising export compliance pressure under EUDR. This chapter frames the operating environment that makes traceable collateral and programmable settlement necessary.","sidebar":"tutorialSidebar"},"the-problem/value-chain-extraction":{"id":"the-problem/value-chain-extraction","title":"2.1 Value Chain Extraction","description":"Middlemen capture 60 to 70 percent of the coffee value chain because farmers have no visibility into forward prices, no verified records to negotiate with, and no alternative source of credit. The farmer who needs cash for fertiliser in February will pre-sell their October harvest at a fraction of its worth to whoever is willing to lend. This is the financing mechanism AsiliChain is designed to replace with on-chain collateral and auto-repaying loans.","sidebar":"tutorialSidebar"},"three-lenses/cooperatives-and-unions":{"id":"three-lenses/cooperatives-and-unions","title":"8.2 For Cooperatives and Cooperative Unions","description":"What changes in your Tuesday morning operations","sidebar":"tutorialSidebar"},"three-lenses/european-buyers-and-auditors":{"id":"three-lenses/european-buyers-and-auditors","title":"8.3 For European Buyers and EUDR Auditors","description":"How compliance cost and shipment risk change","sidebar":"tutorialSidebar"},"three-lenses/mfi-and-impact-investors":{"id":"three-lenses/mfi-and-impact-investors","title":"8.1 For MFI Lenders and Impact Investors","description":"What makes AsiliChain borrowers different from conventional agricultural microfinance clients","sidebar":"tutorialSidebar"},"three-lenses/three-lenses":{"id":"three-lenses/three-lenses","title":"8. AsiliChain Through Three Lenses","description":"By this point, the protocol architecture is defined. This chapter translates that architecture into the decision language of three core stakeholder groups: lenders, cooperatives, and European buyers. Each subsection addresses the evidence, controls, and outcomes that matter most to that audience.","sidebar":"tutorialSidebar"},"uganda-regulatory-architecture/mobile-money-and-kyc":{"id":"uganda-regulatory-architecture/mobile-money-and-kyc","title":"10.3 Mobile Money and KYC Requirements","description":"The National Payments Systems Regulations 2022 updated consumer protection requirements for all institutions operating under the NPS Act, including mobile money providers. Kotani Pay, as the licensed payment service provider converting cUSD to MTN Mobile Money, holds the regulated payment relationship. AsiliChain does not touch the MTN money transmission layer directly and therefore does not require a payment institution licence for the MoMo disbursement function.","sidebar":"tutorialSidebar"},"uganda-regulatory-architecture/regulatory-engagement-sequence":{"id":"uganda-regulatory-architecture/regulatory-engagement-sequence","title":"10.4 Regulatory Engagement Sequence","description":"The following sequence maps regulatory engagement to the roadmap phases. No financial operations should begin before the relevant regulatory conversations have been had.","sidebar":"tutorialSidebar"},"uganda-regulatory-architecture/regulatory-landscape":{"id":"uganda-regulatory-architecture/regulatory-landscape","title":"10.1 The Regulatory Landscape","description":"Uganda\'s financial regulatory environment involves three distinct authorities with overlapping but distinct mandates. Understanding who regulates what is the starting point for every compliance decision.","sidebar":"tutorialSidebar"},"uganda-regulatory-architecture/template-for-other-markets":{"id":"uganda-regulatory-architecture/template-for-other-markets","title":"10.5 Template for Other African Markets","description":"Uganda\'s framework becomes the template. Kenya\'s equivalent regulators are the Central Bank of Kenya (CBK) for payment systems, the Sacco Societies Regulatory Authority (SASRA) for cooperative lending, and the Kenya Coffee Directorate (KCD) for sector oversight. Rwanda\'s equivalents are the National Bank of Rwanda (BNR), the Rwanda Cooperative Agency (RCA), and the National Agriculture Export Development Board (NAEB). Each expansion market requires a country-specific legal opinion on the same three questions: technology provider versus lender classification, payment service provider requirements for the MoMo off-ramp, and sector authority partnership for cooperative registry access.","sidebar":"tutorialSidebar"},"uganda-regulatory-architecture/tiered-lending-framework":{"id":"uganda-regulatory-architecture/tiered-lending-framework","title":"10.2 The Tiered Lending Framework","description":"Uganda\'s lending sector is structured in four tiers under the Financial Institutions Act (as amended) and the Tier 4 Microfinance Institutions and Money Lenders Act 2016. The LendingVault operates as an interface layer between licensed MFI lenders (Tier III or Tier IV) and cooperative borrowers. The key regulatory question is whether the LendingVault itself constitutes a lending business requiring UMRA licensing, or whether it functions as a technology platform through which licensed lenders deploy capital.","sidebar":"tutorialSidebar"},"uganda-regulatory-architecture/uganda-regulatory-architecture":{"id":"uganda-regulatory-architecture/uganda-regulatory-architecture","title":"10. Uganda Regulatory Architecture","description":"Uganda is the launch market. Getting the regulatory architecture right here is both a legal requirement and the template for expansion into Kenya, Rwanda, and Ethiopia. This chapter maps each regulated protocol activity to the relevant Ugandan regulator, legal basis, and implementation pathway.","sidebar":"tutorialSidebar"},"visual-index":{"id":"visual-index","title":"19. Visual Index","description":"This page indexes all visuals currently embedded in the whitepaper docs.","sidebar":"tutorialSidebar"}}}}')}}]);